const interviews = $('Upcoming Interviews').all().map(i => i.json);
const offers = $('Pending Offers').all().map(i => i.json);
const activity = $('This Week Activity').first().json;
const snapshot = $('Pipeline Snapshot').all().map(i => i.json);
const sources = $('Source Performance').all().map(i => i.json);
const followups = $('Follow-Ups Due').all().map(i => i.json);

const now = new Date();
const weekStart = new Date(now);
weekStart.setDate(now.getDate() - 7);
const dateRange = `${weekStart.toLocaleDateString('en-GB', {day:'numeric',month:'short'})} - ${now.toLocaleDateString('en-GB', {day:'numeric',month:'short',year:'numeric'})}`;

// Build pipeline summary
let corporateTotal = 0, academicTotal = 0;
const stateRows = {};
for (const s of snapshot) {
    if (!s.pipeline_track) continue;
    const key = s.current_state;
    if (!stateRows[key]) stateRows[key] = { corporate: 0, academic: 0 };
    stateRows[key][s.pipeline_track] = parseInt(s.count) || 0;
    if (s.pipeline_track === 'corporate') corporateTotal += parseInt(s.count) || 0;
    else academicTotal += parseInt(s.count) || 0;
}

let pipelineHtml = '<table style="width:100%;border-collapse:collapse;">';
pipelineHtml += '<tr style="background:#f3f4f6;"><th style="padding:8px;text-align:left;border:1px solid #e5e7eb;">Stage</th><th style="padding:8px;text-align:center;border:1px solid #e5e7eb;">Corporate</th><th style="padding:8px;text-align:center;border:1px solid #e5e7eb;">Academic</th></tr>';
const stageOrder = ['shortlisted','cv_tailored','applied','acknowledged','screening','interviewing','assessment','offer_received','negotiating','pre_employment','academic_longlisted','academic_shortlisted'];
for (const stage of stageOrder) {
    if (!stateRows[stage]) continue;
    const label = stage.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
    pipelineHtml += `<tr><td style="padding:6px 8px;border:1px solid #e5e7eb;">${label}</td><td style="padding:6px 8px;text-align:center;border:1px solid #e5e7eb;">${stateRows[stage].corporate || 0}</td><td style="padding:6px 8px;text-align:center;border:1px solid #e5e7eb;">${stateRows[stage].academic || 0}</td></tr>`;
}
pipelineHtml += `<tr style="font-weight:bold;background:#f3f4f6;"><td style="padding:8px;border:1px solid #e5e7eb;">Total Active</td><td style="padding:8px;text-align:center;border:1px solid #e5e7eb;">${corporateTotal}</td><td style="padding:8px;text-align:center;border:1px solid #e5e7eb;">${academicTotal}</td></tr></table>`;

// Interviews section
let interviewsHtml = '';
if (interviews.length > 0 && interviews[0].application_id) {
    interviewsHtml = '<h3 style="color:#dc2626;">Upcoming Interviews</h3><ul>';
    for (const iv of interviews) {
        const dt = iv.scheduled_at ? new Date(iv.scheduled_at).toLocaleDateString('en-GB', {weekday:'short',day:'numeric',month:'short',hour:'2-digit',minute:'2-digit'}) : 'TBC';
        interviewsHtml += `<li><strong>${iv.job_title}</strong> at ${iv.company_name} — ${dt} (${iv.interview_type || 'interview'}${iv.platform ? ', ' + iv.platform : ''})</li>`;
    }
    interviewsHtml += '</ul>';
} else {
    interviewsHtml = '<p style="color:#6b7280;">No interviews scheduled for next week.</p>';
}

// Offers section
let offersHtml = '';
if (offers.length > 0 && offers[0].company_name) {
    offersHtml = '<h3 style="color:#059669;">Pending Offers</h3><ul>';
    for (const o of offers) {
        offersHtml += `<li><strong>${o.job_title}</strong> at ${o.company_name} (${o.current_state.replace(/_/g, ' ')})</li>`;
    }
    offersHtml += '</ul>';
}

// Activity section
let activityHtml = `<h3>This Week\'s Activity</h3><table style="width:100%;border-collapse:collapse;">`;
activityHtml += `<tr><td style="padding:6px 8px;">Applications submitted</td><td style="padding:6px 8px;font-weight:bold;">${activity.apps_this_week || 0}</td></tr>`;
activityHtml += `<tr><td style="padding:6px 8px;">Acknowledgements received</td><td style="padding:6px 8px;font-weight:bold;">${activity.acks_this_week || 0}</td></tr>`;
activityHtml += `<tr><td style="padding:6px 8px;">Interviews secured</td><td style="padding:6px 8px;font-weight:bold;">${activity.interviews_this_week || 0}</td></tr>`;
activityHtml += `<tr><td style="padding:6px 8px;">Rejections</td><td style="padding:6px 8px;font-weight:bold;">${activity.rejections_this_week || 0}</td></tr>`;
activityHtml += `<tr><td style="padding:6px 8px;">Ghosted detections</td><td style="padding:6px 8px;font-weight:bold;">${activity.ghosted_this_week || 0}</td></tr>`;
activityHtml += '</table>';

// Sources section
let sourcesHtml = '';
if (sources.length > 0 && sources[0].source) {
    sourcesHtml = '<h3>Source Performance</h3><table style="width:100%;border-collapse:collapse;">';
    sourcesHtml += '<tr style="background:#f3f4f6;"><th style="padding:8px;text-align:left;border:1px solid #e5e7eb;">Source</th><th style="padding:8px;text-align:center;border:1px solid #e5e7eb;">Applied</th><th style="padding:8px;text-align:center;border:1px solid #e5e7eb;">Responded</th><th style="padding:8px;text-align:center;border:1px solid #e5e7eb;">Rate</th></tr>';
    for (const s of sources) {
        sourcesHtml += `<tr><td style="padding:6px 8px;border:1px solid #e5e7eb;">${s.source}</td><td style="padding:6px 8px;text-align:center;border:1px solid #e5e7eb;">${s.total}</td><td style="padding:6px 8px;text-align:center;border:1px solid #e5e7eb;">${s.responded}</td><td style="padding:6px 8px;text-align:center;border:1px solid #e5e7eb;">${s.response_pct}%</td></tr>`;
    }
    sourcesHtml += '</table>';
}

// Follow-ups section
let followupsHtml = '';
if (followups.length > 0 && followups[0].company_name) {
    followupsHtml = '<h3>Follow-Ups Due This Week</h3><ul>';
    for (const f of followups) {
        followupsHtml += `<li><strong>${f.job_title}</strong> at ${f.company_name} (${f.pipeline_track})</li>`;
    }
    followupsHtml += '</ul>';
}

// Assemble full email
const fullHtml = `<div style="font-family: Arial, sans-serif; max-width: 700px; margin: 0 auto; padding: 20px;">
    <h1 style="color: #1e40af; border-bottom: 2px solid #3b82f6; padding-bottom: 10px;">Weekly Pipeline Summary</h1>
    <p style="color: #6b7280;">${dateRange}</p>

    ${interviewsHtml}
    ${offersHtml}

    <h3>Pipeline Snapshot</h3>
    ${pipelineHtml}

    ${activityHtml}
    ${followupsHtml}
    ${sourcesHtml}

    <hr style="border: 1px solid #e5e7eb; margin-top: 30px;">
    <p style="color: #9ca3af; font-size: 11px;">Selvi Job Tracker | Weekly Pipeline Report | Generated ${now.toISOString()}</p>
</div>`;

const subject = `Weekly Pipeline Summary — ${dateRange}`;

return [{ json: {
    subject,
    html: fullHtml,
    activeCount: corporateTotal + academicTotal,
    dateRange
}}];

